  1	import { Label, Stack, StackItem, Title, TitleSizes, Tooltip, TooltipPosition } from '@patternfly/react-core';
  2	import { Labels } from 'components/Label/Labels';
  3	import { PFBadge, PFBadges } from 'components/Pf/PfBadges';
  4	import { LocalTime } from 'components/Time/LocalTime';
  5	import { ValidationObjectSummary } from 'components/Validations/ValidationObjectSummary';
  6	import { GVKToBadge } from 'components/VirtualList/Config';
  7	import { KialiIcon } from 'config/KialiIcon';
  8	import * as React from 'react';
  9	import { IstioConfigDetails } from 'types/IstioConfigDetails';
 10	import {
 11	  HelpMessage,
 12	  ObjectReference,
 13	  ObjectValidation,
 14	  ServiceReference,
 15	  ValidationMessage,
 16	  ValidationTypes,
 17	  WorkloadReference
 18	} from 'types/IstioObjects';
 19	import { kialiStyle } from 'styles/StyleUtils';
 20	import {
 21	  getGVKTypeString,
 22	  getIstioObject,
 23	  getIstioObjectGVK,
 24	  getReconciliationCondition
 25	} from 'utils/IstioConfigUtils';
 26	import { IstioConfigHelp } from './IstioConfigHelp';
 27	import { IstioConfigReferences } from './IstioConfigReferences';
 28	import { IstioConfigValidationReferences } from './IstioConfigValidationReferences';
 29	import { IstioStatusMessageList } from './IstioStatusMessageList';
 30	import { KioskElement } from '../../../components/Kiosk/KioskElement';
 31	import { PFColors } from '../../../components/Pf/PfColors';
 32	import { GetIstioObjectUrl } from '../../../components/Link/IstioObjectLink';
 33	import { homeCluster, isMultiCluster, serverConfig } from '../../../config';
 34	import { CLUSTER_DEFAULT } from 'types/Graph';
 35	import { infoStyle } from 'styles/IconStyle';
 36	
 37	interface IstioConfigOverviewProps {
 38	  cluster?: string;
 39	  helpMessages?: HelpMessage[];
 40	  istioAPIEnabled: boolean;
 41	  istioObjectDetails: IstioConfigDetails;
 42	  istioValidations?: ObjectValidation;
 43	  kiosk: string;
 44	  namespace: string;
 45	  objectReferences: ObjectReference[];
 46	  selectedLine?: string;
 47	  serviceReferences: ServiceReference[];
 48	  statusMessages: ValidationMessage[];
 49	  workloadReferences: WorkloadReference[];
 50	}
 51	
 52	const iconStyle = kialiStyle({
 53	  display: 'inline-block'
 54	});
 55	
 56	const warnStyle = kialiStyle({
 57	  marginRight: '0.125rem'
 58	});
 59	
 60	const healthIconStyle = kialiStyle({
 61	  marginLeft: '0.5rem'
 62	});
 63	
 64	const resourceListStyle = kialiStyle({
 65	  $nest: {
 66	    '& > ul > li > span': {
 67	      float: 'left',
 68	      width: '125px',
 69	      fontWeight: 700
 70	    }
 71	  }
 72	});
 73	
 74	const linkStyle = kialiStyle({
 75	  marginLeft: '0.25rem',
 76	  fontSize: '85%',
 77	  color: PFColors.Link
 78	});
 79	
 80	export const IstioConfigOverview: React.FC<IstioConfigOverviewProps> = (props: IstioConfigOverviewProps) => {
 81	  const configurationHasWarnings = (): boolean | undefined => {
 82	    return props.istioValidations?.checks.some(check => {
 83	      return check.severity === ValidationTypes.Warning;
 84	    });
 85	  };
 86	  const hasReferences = (): boolean => {
 87	    return (
 88	      props.objectReferences.length > 0 || props.serviceReferences.length > 0 || props.workloadReferences.length > 0
 89	    );
 90	  };
 91	
 92	  const istioObject = getIstioObject(props.istioObjectDetails);
 93	
 94	  const resourceProperties = (
 95	    <div key="properties-list" className={resourceListStyle}>
 96	      <ul style={{ listStyleType: 'none' }}>
 97	        {istioObject && istioObject.metadata.creationTimestamp && (
 98	          <li>
 99	            <span>Created</span>
100	
101	            <div style={{ display: 'inline-block' }}>
102	              <LocalTime time={istioObject.metadata.creationTimestamp} />
103	            </div>
104	          </li>
105	        )}
106	
107	        {istioObject && istioObject.metadata.resourceVersion && (
108	          <li>
109	            <span>Version</span>
110	            {istioObject.metadata.resourceVersion}
111	          </li>
112	        )}
113	      </ul>
114	    </div>
115	  );
116	
117	  let urlInKiali = '';
118	
119	  if (istioObject !== undefined && istioObject.metadata.namespace !== undefined && istioObject.kind !== undefined) {
120	    const clusterInfo = serverConfig.clusters[props.cluster ?? homeCluster?.name ?? CLUSTER_DEFAULT];
121	    const kialiInstance = clusterInfo?.kialiInstances?.find(instance => instance.url.length !== 0);
122	
123	    // Set the kiali url from kialiInstance info (here a "/console" is required as external link is used)
124	    const kialiUrl = `${kialiInstance?.url ?? ''}/console`;
125	    urlInKiali =
126	      kialiUrl +
127	      GetIstioObjectUrl(
128	        istioObject.metadata.name,
129	        istioObject.metadata.namespace,
130	        getIstioObjectGVK(istioObject.apiVersion, istioObject.kind),
131	        props.cluster
132	      );
133	  }
134	
135	  return (
136	    <Stack hasGutter={true}>
137	      <StackItem>
138	        <Title headingLevel="h3" size={TitleSizes.xl}>
139	          Overview
140	        </Title>
141	      </StackItem>
142	
143	      <StackItem>
144	        {isMultiCluster && (
145	          <div key="cluster-icon">
146	            <PFBadge badge={PFBadges.Cluster} position={TooltipPosition.right} /> {props.cluster}
147	          </div>
148	        )}
149	
150	        {istioObject && istioObject.kind && (
151	          <>
152	            <div className={iconStyle}>
153	              <PFBadge
154	                badge={GVKToBadge[getGVKTypeString(getIstioObjectGVK(istioObject.apiVersion, istioObject.kind))]}
155	                position={TooltipPosition.top}
156	              />
157	            </div>
158	
159	            {istioObject?.metadata.name}
160	
161	            <Tooltip
162	              position={TooltipPosition.right}
163	              content={<div style={{ textAlign: 'left' }}>{resourceProperties}</div>}
164	            >
165	              <KialiIcon.Info className={infoStyle} />
166	            </Tooltip>
167	
168	            {props.istioValidations &&
169	              (!props.statusMessages || props.statusMessages.length === 0) &&
170	              (!props.istioValidations.checks || props.istioValidations.checks.length === 0) && (
171	                <span className={healthIconStyle}>
172	                  <ValidationObjectSummary
173	                    id="config-validation"
174	                    validations={[props.istioValidations]}
175	                    reconciledCondition={getReconciliationCondition(props.istioObjectDetails)}
176	                  />
177	                </span>
178	              )}
179	          </>
180	        )}
181	      </StackItem>
182	
183	      {istioObject?.metadata.labels && (
184	        <StackItem>
185	          <Labels tooltipMessage="Labels defined on this resource" labels={istioObject?.metadata.labels}></Labels>
186	        </StackItem>
187	      )}
188	
189	      {((props.statusMessages && props.statusMessages.length > 0) ||
190	        (props.istioValidations && props.istioValidations.checks && props.istioValidations.checks.length > 0)) && (
191	        <StackItem>
192	          <IstioStatusMessageList messages={props.statusMessages} checks={props.istioValidations?.checks} />
193	        </StackItem>
194	      )}
195	
196	      {props.istioValidations?.references && (
197	        <StackItem>
198	          <IstioConfigValidationReferences
199	            objectReferences={props.istioValidations.references}
200	            cluster={props.cluster}
201	          />
202	        </StackItem>
203	      )}
204	
205	      {((!props.istioValidations && hasReferences()) ||
206	        (props.istioValidations?.valid && !configurationHasWarnings())) && (
207	        <StackItem>
208	          <IstioConfigReferences
209	            objectReferences={props.objectReferences}
210	            serviceReferences={props.serviceReferences}
211	            workloadReferences={props.workloadReferences}
212	            isValid={!props.istioValidations || props.istioValidations?.valid}
213	            cluster={props.cluster}
214	          />
215	        </StackItem>
216	      )}
217	
218	      {props.helpMessages && props.helpMessages.length > 0 && (
219	        <StackItem>
220	          <IstioConfigHelp helpMessages={props.helpMessages} selectedLine={props.selectedLine}></IstioConfigHelp>
221	        </StackItem>
222	      )}
223	
224	      {!props.istioAPIEnabled && props.cluster === homeCluster?.name && (
225	        <StackItem>
226	          <KialiIcon.Warning className={warnStyle} /> <b>Istio API is disabled.</b> Be careful when editing the
227	          configuration as the Istio config validations are disabled when the Istio API is disabled.
228	        </StackItem>
229	      )}
230	
231	      <KioskElement>
232	        <StackItem>
233	          <Tooltip
234	            content="This is a Read only view of the YAML including Validations. It is possible to edit directly in Kiali "
235	            position={TooltipPosition.top}
236	          >
237	            <Label color="green" isCompact>
238	              Read only mode
239	            </Label>
240	          </Tooltip>
241	
242	          <a href={urlInKiali} className={linkStyle} target="_blank" rel="noreferrer">
243	            Edit in Kiali
244	          </a>
245	        </StackItem>
246	      </KioskElement>
247	    </Stack>
248	  );
249	};

